  <HEADER encrypted="1" encrypted_ver="1" build="0.0704.1001.0000.13.0" user="z" computer="DESKTOP-LC5V468" date="2025.06.30 23'00'47" map_xs="128" map_ys="128" north_angle="-357913942" extra_map_edge="1" tileset="volcanic" environment="Volcanic_final" players="6" name="Переправа Сайны" id="sayna_pass" style="0" description="После Сайны, сгинувшего в этой полыхающей расщелине, главенствующим в пантеоне местных обитателей стал Икс, Бог Луны. Большинство построек охраняется Падшими квотлами, однако остерегайтесь и враждебных саламандр. Каждый игрок получит два города для экспансии и по одному дополнительному городу будет лежать на каждой стороне расщелины, а в центре же может распологаться и сам Храм Луны. &#xA; {— Официальная карта в редакции Матвея Icpompeo Аль-Бороди.}" enable_dominance="1" preview_image_ext="tga" version="12" allowable_game_styles="4294967295" default_game_style="-1" victory="0" elimination="1" allies="12" living_world_bird="0" force_rush_rules_disable="0" does_override_teamstyle="0" teamstyle_override_value="0" starts_required="0" starts_no_pick="0" show_all_villages="1" generate_script="0" num_villages="0" num_special="0" num_villages_override="14-15" num_special_override="18-19">
